<?php
class RewardController { public static function me(): void { Response::json(true,'Data berhasil dimuat',['points'=>120,'streak_days'=>2,'checked_in_today'=>false,'missions'=>[]]); } public static function checkin(): void { Response::json(false,'Anda sudah check-in hari ini',null,[],400);} public static function vouchers(): void { $s=Database::connection()->query('SELECT * FROM vouchers WHERE status="active"'); Response::json(true,'Data berhasil dimuat',$s->fetchAll()); } public static function redeem($id): void { Response::json(false,'Poin belum cukup untuk voucher ini',null,[],400);} }
